```verilog
`timescale 1ns/1ps
module counter_tb;
  reg clk;
  reg rst;
  wire [3:0] count;
  integer i;

  // Instantiate DUT
  counter uut (.clk(clk), .rst(rst), .count(count));

  // 10ns clock period
  initial clk = 0;
  always #5 clk = ~clk;

  task check;
    input [3:0] expected;
    begin
      if (count !== expected)
        $error("FAIL at time %0t: expected %0d, got %0d", $time, expected, count);
      else
        $display("PASS: count=%0d at time %0t", count, $time);
    end
  endtask

  initial begin
    $dumpfile("counter.vcd");
    $dumpvars(0, counter_tb);

    // Test reset
    rst = 1;
    @(posedge clk); #1;
    check(0);

    // Release reset, count through all 16 states
    rst = 0;
    for (i = 1; i <= 16; i = i + 1) begin
      @(posedge clk); #1;
      check(i % 16);
    end

    // Test mid-count reset
    @(posedge clk); #1;
    rst = 1;
    @(posedge clk); #1;
    check(0);
    rst = 0;

    $display("All tests completed.");
    $finish;
  end
endmodule
```

