module adder(input [3:0] a, input [3:0] b, output [3:0] sum);
  assign sum = a + b;
endmodule

response:
```verilog
module fifo_16x8 (
  input        clk,
  input        rst,
  input        wr_en,
  input        rd_en,
  input  [7:0] din,
  output reg [7:0] dout,
  output       full,
  output       empty
);
  reg [7:0] mem [0:15];
  reg [4:0] wr_ptr = 0;  // 5 bits to detect wrap
  reg [4:0] rd_ptr = 0;

  wire [4:0] count = wr_ptr - rd_ptr;
  assign full  = (count == 5'd16);
  assign empty = (count == 5'd0);

  always @(posedge clk) begin
    if (rst) begin
      wr_ptr <= 0;
      rd_ptr <= 0;
    end else begin
      // Write
      if (wr_en && !full) begin
        mem[wr_ptr[3:0]] <= din;
        wr_ptr <= wr_ptr + 1;
      end
      // Read
      if (rd_en && !empty) begin
        dout   <= mem[rd_ptr[3:0]];
        rd_ptr <= rd_ptr + 1;
      end
    end
  end
endmodule
```

**Design Notes:**
- Uses 5-bit pointers (extra bit for full/empty disambiguation — classic technique).
- Simultaneous read+write when not full/empty is safe.
- **Timing Note:** For multi-clock FIFO (async), use Gray-coded pointers and two-flop synchronizers on each pointer.
